Here is the entire function code: suspend fun parseAndAddGames(url: String, context: Context, dbName: String, isAddon: Boolean) = withContext(Dispatchers.IO) {
    val connection = URL(url).openConnection() as HttpURLConnection
    connection.requestMethod = "GET"
    connection.connect()
    val inputStream = connection.inputStream
    try {
        val xmlString = inputStream.bufferedReader().use { it.readText() }
        val parser = XmlPullParserFactory.newInstance().newPullParser()
        parser.setInput(StringReader(xmlString))
        var eventType = parser.eventType
        var gameID: Long = 0
        var isOwned: Boolean = false
        var name: String? = null
        var year: Int = 0
        var rank: Int = 0
        var thumb: String? = null
        var type: Int
        if (isAddon) {
            type = 1
            Log.d("XML", "Addons")
        }
        else {
            type = 0
            Log.d("XML", "Games")
        }
        while (eventType != XmlPullParser.END_DOCUMENT) {
            when (eventType) {
                XmlPullParser.START_TAG -> {
                    when (parser.name) {
                        "item" -> {
                            gameID = parser.getAttributeValue(null, "objectid").toLong()
                        }
                        "name" -> {
                            name = parser.nextText()
                        }
                        "yearpublished" -> {
                            year = parser.nextText().toInt()
                        }
                        "thumbnail" -> {
                            thumb = parser.nextText()
                        }
                        "status" -> {
                            isOwned = parser.getAttributeValue(null, "own") == "1"
                            }
                        "rank" -> {
                            if (parser.getAttributeValue(null, "type") == "subtype") {
                                rank = parser.getAttributeValue(null, "value").toInt()
                            }
                        }
                        }
                    }
                XmlPullParser.END_TAG -> {
                    if (parser.name == "item") {
                        if (isOwned) {
                            Log.d("XML", "Game: $gameID, $name, $year, $thumb, $type, $rank")
                            val db = GameDB(context, dbName, null, 1)
                            if (name != null && thumb != null) {
                                db.addGame(gameID, name, year, thumb, type, rank)
                            }
                            gameID = 0
                            name = null
                            year = 0
                            thumb = null
                            isOwned = false
                            //type = 0
                            rank = 0
                        }
                    }
                }
            }
            eventType = parser.next()
        }

    } catch (e: IOException) {
        Toast.makeText(context, "Błąd pobierania pliku XML", Toast.LENGTH_SHORT).show()
    } catch (e: XmlPullParserException) {
        Toast.makeText(context, "Błąd czytania pliku XML", Toast.LENGTH_SHORT).show()
    } finally {
        inputStream.close()
    }
}

You can use `viewModelScope` to launch a coroutine that runs the database operation. If you use `viewModelScope`, the coroutine will be tied to the lifecycle of the ViewModel, which will ensure that it runs until the database operation is complete, even if the current activity is destroyed.

Here's an example of how you can use `viewModelScope` to launch a coroutine and ensure that it finishes before moving to the second activity:

```kotlin
class FirstActivity : AppCompatActivity() {

    private lateinit var viewModel: MyViewModel

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_first)

        viewModel = ViewModelProvider(this).get(MyViewModel::class.java)

        viewModel.createData().observe(this, Observer { success ->
            if (success) {
                startActivity(Intent(this, SecondActivity::class.java))
                finish()
            } else {
                // handle database create error
            }
        })
    }
}

class MyViewModel(application: Application) : AndroidViewModel(application) {

    fun createData(): LiveData<Boolean> {
        val successLiveData = MutableLiveData<Boolean>()

        viewModelScope.launch {
            try {
                // Run your database operation here
                val result = myDatabase.createData()

                // Set the result on the LiveData
                successLiveData.postValue(result)
            } catch (e: Exception) {
                // Handle error during database operation
                successLiveData.postValue(false)
            }
        }

        return successLiveData
    }
}
```

In this example, `MyViewModel` creates a coroutine and runs the `createData()` function. When the function completes, it sets the result on a `LiveData` object, which is then observed by the first activity. If the database operation is successful, `createData()` returns `true` and the first activity starts the second activity. Otherwise, it returns `false`, and the first activity can handle the error however it wants.

Yes, there are other ways to make sure that the database operation finishes before moving to the second activity:

1. Use `CoroutineScope` to create a new coroutine in a new scope. Start the coroutine in `onCreate()` of the activity that executes the database operation, and then call `join()` on the coroutine before moving to the second activity. Here's an example:

```kotlin
class MainActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        CoroutineScope(Dispatchers.Default).launch {
            // Do database operation
        }.join()

        startActivity(Intent(this, SecondActivity::class.java))
        finish()
    }
}
```

In this example, the `launch` function starts the coroutine, and `join` function blocks the current thread until the coroutine completes its execution.

2. You can also use a `CountDownLatch` to wait for the database operation to complete before moving to the second activity:

```kotlin
class MainActivity : AppCompatActivity() {

    private val latch = CountDownLatch(1)

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        CoroutineScope(Dispatchers.Default).launch {
            // Do database operation

            // Signal that the database operation is complete
            latch.countDown()
        }

        // Wait until the database operation is complete
        latch.await()

        startActivity(Intent(this, SecondActivity::class.java))
        finish()
    }
}
```

In this example, the `await` function blocks the current thread until the `countDown()` function is called on the `CountDownLatch`. 

Note that these examples assume that `MyDatabase` is a suspend function. If it's not a suspend function, wrap it in a coroutine block.

It's possible that the progress bar is not configured correctly or it is not being used in the best way to provide feedback to the user. Here are some tips to help you use the progress bar effectively:

1. Define the progress bar in your layout xml file, and set its visibility to `invisible` by default.

2. In the activity's `onCreate()` method, get a reference to the progress bar using the `findViewById()` method.

3. Before you start the long-running operation, set the progress bar to `visible` using `progressBar.visibility = View.VISIBLE`.

4. To update the progress, use the `setProgress()` method of the progress bar, passing in an integer value between `0` and `100` that represents the percentage of the operation that is complete. For example, you can use `progressBar.setProgress(50)` to set the progress to 50%.

5. After the operation is complete, set the progress bar back to `invisible` using `progressBar.visibility = View.INVISIBLE`.

Here's an example of how you can use the progress bar in your activity:

```kotlin
class MyActivity : AppCompatActivity() {

    // Define the progress bar
    private lateinit var progressBar: ProgressBar

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_my)

        // Get a reference to the progress bar
        progressBar = findViewById(R.id.progress_bar)

        // Hide the progress bar by default
        progressBar.visibility = View.INVISIBLE

        // Start a long-running operation
        CoroutineScope(Dispatchers.Default).launch {
            // Show the progress bar
            withContext(Dispatchers.Main) {
                progressBar.visibility = View.VISIBLE
            }

            // Do the long-running operation and update the progress
            for (i in 0..100) {
                // Do a small part of the operation
                delay(50)

                // Update the progress
                withContext(Dispatchers.Main) {
                    progressBar.progress = i
                }
            }

            // Hide the progress bar when the operation is complete
            withContext(Dispatchers.Main) {
                progressBar.visibility = View.INVISIBLE
            }
        }
    }
}
```

In this example, the progress bar is defined in the activity's layout xml file, and is then retrieved in the `onCreate()` method using `findViewById()`. The progress bar is set to `invisible` by default. 

When the long-running operation starts, the progress bar is set to `visible`, and then updated in a loop that simulates the progress of the operation. Finally, when the operation is complete, the progress bar is set back to `invisible`. 

Remember to use the progress bar in a way that provides feedback to the user and fits with the user experience of your application.

If you are using an indefinite progress bar, you can use the `isIndeterminate` property to indicate that the progress bar should be indefinite. 

Here's an example of how you can use an indefinite progress bar in your activity:
```kotlin
class MyActivity : AppCompatActivity() {

    // Define the progress bar
    private lateinit var progressBar: ProgressBar

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_my)

        // Get a reference to the progress bar
        progressBar = findViewById(R.id.progress_bar)

        // Set the progress bar to be indefinite
        progressBar.isIndeterminate = true

        // Show the progress bar
        progressBar.visibility = View.VISIBLE

        // Start a long-running operation
        CoroutineScope(Dispatchers.Default).launch {

            // Do the long-running operation

            // Hide the progress bar when the operation is complete
            withContext(Dispatchers.Main) {
                progressBar.visibility = View.INVISIBLE
            }
        }
    }
}
```

In this example, the progress bar is defined in the activity's layout xml file, and is then retrieved in the `onCreate()` method using `findViewById()`. The progress bar is set to be indefinite using the `isIndeterminate` property. 

When the long-running operation starts, the progress bar is set to `visible`. The operation runs indefinitely until it is complete, and the progress bar is set to `invisible` when the operation is complete.

Remember that an indefinite progress bar provides feedback to the user that an operation is running and that the progress is not deterministic. If you are not providing any deterministic feedback to the user, then it might be helpful to include a message that indicates what is happening or why the operation is taking a long time.
